const email = $input.item.json;
const keywords = ($vars['ACTION_KEYWORDS'] || 'ACTION REQUIRED,URGENT,TASK:,PLEASE REVIEW,CRITICAL').split(',').map(k => k.trim().toLowerCase());
const subject = (email.subject || '').toLowerCase();
const rawBody = (email.body?.content || '');
const cleanBody = rawBody.replace(/<(style|script)[^>]*>[\s\S]*?<\/\1>/gi, ' ').replace(/<[^>]*>/g, ' ').replace(/&nbsp;/gi, ' ').replace(/\s+/g, ' ').trim();
const bodyText = cleanBody.toLowerCase();
const combined = subject + ' ' + bodyText;
const matchedKeyword = keywords.find(kw => combined.includes(kw));
if (!matchedKeyword) { return { json: { emailId: email.id, matchedKeyword: '' } }; }
const isUrgent = ['urgent', 'critical'].some(k => combined.includes(k));
const priority = isUrgent ? 1 : 5;
// Fix 4: timezone from workflow variable with env fallback
const tz = $vars['REPORT_TIMEZONE'] || process.env.REPORT_TIMEZONE || 'Europe/Helsinki';
const helsinkiNow = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
let dueDate = null;
const isoMatch = cleanBody.match(/\b(\d{4}-\d{2}-\d{2})\b/);
const structuredMatch = cleanBody.match(/(due:|by:)\s*(\d{1,2}[.\/\-]\d{1,2}[.\/\-]\d{2,4})/i);
const relativeMatch = cleanBody.match(/\b(today|tomorrow|eod|end of day|end of week|friday|monday)\b/i);
if (isoMatch) { dueDate = isoMatch[1] + 'T23:59:59Z'; }
else if (structuredMatch) { const raw = structuredMatch[2]; const parts = raw.split(/[.\/\-]/); if (parts.length === 3) { const y = parts[0].length === 4 ? parts[0] : '20' + parts[2]; const m = (parts[0].length === 4 ? parts[1] : parts[1]).padStart(2, '0'); const d = (parts[0].length === 4 ? parts[2] : parts[0]).padStart(2, '0'); dueDate = `${y}-${m}-${d}T23:59:59Z`; } }
else if (relativeMatch) { const phrase = relativeMatch[1].toLowerCase(); const target = new Date(helsinkiNow); if (phrase === 'tomorrow') { target.setDate(target.getDate() + 1); } else if (phrase === 'end of week' || phrase === 'friday') { const day = target.getDay(); target.setDate(target.getDate() + ((5 - day + 7) % 7 || 7)); } else if (phrase === 'monday') { const day = target.getDay(); target.setDate(target.getDate() + ((1 - day + 7) % 7 || 7)); } target.setHours(23, 59, 59, 0); const utcOffset = new Date(target.toLocaleString('en-US', { timeZone: tz })) - target; const utcTarget = new Date(target.getTime() - utcOffset); dueDate = utcTarget.toISOString(); }
const taskTitle = `[EMAIL] ${email.subject || 'No Subject'}`;
const senderName = email.from?.emailAddress?.name || 'Unknown';
const senderEmail = email.from?.emailAddress?.address || '';
const received = email.receivedDateTime || new Date().toISOString();
const bodyPreview = cleanBody.substring(0, 500);
const taskNotes = `From: ${senderName} <${senderEmail}>\nReceived: ${received}\nKeyword trigger: ${matchedKeyword.toUpperCase()}\n\n${bodyPreview}`;
return { json: { emailId: email.id, emailSubject: email.subject, senderName, senderEmail, receivedDateTime: email.receivedDateTime, taskTitle, taskNotes, priority, dueDate, matchedKeyword, isUrgent, importance: email.importance || 'normal' } };

const emailId = $('Extract Task from Email').item.json?.emailId || 'unknown';
const subject = $('Extract Task from Email').item.json?.emailSubject || 'unknown';
const nodesToCheck = ['Create Planner Task','Set Task Details (Notes)','Post Teams Notification','Reply, Categorize & Mark Read','Mark as Read After Reply'];
let errorSummary = null;
for (const nodeName of nodesToCheck) {
  try { const result = $node[nodeName]?.outputData?.main?.[0]?.[0]; if (result?.error) { errorSummary = { failedNode: nodeName, error: result.error.message, emailId, subject }; break; } } catch(e) { }
}
return { json: { emailId, subject, hadError: !!errorSummary, errorSummary } };

const response = $input.item.json;
const scoreData = (response.value && response.value[0]) ? response.value[0] : response;
const currentScore = scoreData.currentScore || 0;
const maxScore = scoreData.maxScore || 1;
const percentage = ((currentScore / maxScore) * 100).toFixed(1);
// Fix 4: timezone from workflow variable with env fallback
const tz = $vars['REPORT_TIMEZONE'] || process.env.REPORT_TIMEZONE || 'Europe/Helsinki';
const scanDate = scoreData.createdDateTime ? new Date(scoreData.createdDateTime).toLocaleDateString('fi-FI', { timeZone: tz }) : new Date().toLocaleDateString('fi-FI', { timeZone: tz });
const isHealthy = parseFloat(percentage) >= 80.0;
return { json: { scanDate, currentScore, maxScore, percentage, isHealthy, activeUserCount: scoreData.activeUserCount || 'Unknown' } };

