const tasks = $input.all()[0].json.value || [];
const existing = tasks.find(t => t.title.startsWith('🚨 Security Score Alert') && t.percentComplete < 100);
const taskId = existing?.id || null;
const scoreData = $('Calculate Security Score Percentage').first().json;
return { json: { existingTaskId: taskId, percentage: scoreData.percentage, currentScore: scoreData.currentScore, maxScore: scoreData.maxScore, scanDate: scoreData.scanDate } };

